def compute_context_vector(tokens, position, window=2):
    context = np.zeros(2048)
    for offset in range(-window, window + 1):
        if offset == 0:
            continue  # skip the word itself
        idx = position + offset
        if 0 <= idx < len(tokens):
            weight = 1.0 / abs(offset)  # closer = stronger
            context += weight * grammar_vector(tokens[idx])
    return normalize(context)

def disambiguate(word, context_vec):
    noun_sim = cosine_similarity(context_vec, templates[word]['NOUN'].centroid)
    verb_sim = cosine_similarity(context_vec, templates[word]['VERB'].centroid)

    if noun_sim > verb_sim:
        return 'NOUN', noun_sim - verb_sim  # confidence = margin
    else:
        return 'VERB', verb_sim - noun_sim
